import { useEffect, useRef } from 'react';
import { useLocation, useNavigate } from 'react-router-dom';
import { isStandalone } from '../dev/isStandalone';

const LINM_SHELL_PREFIX = '/kpi';

function stripShellPrefix(path: string): string {
  if (path.startsWith(LINM_SHELL_PREFIX)) {
    return path.slice(LINM_SHELL_PREFIX.length) || '/';
  }
  return path;
}

/**
 * Keeps MemoryRouter aligned with the browser address bar.
 * - MFE (Root): window → memory (single-spa nav, back/forward)
 * - Standalone (`yarn start:std`): memory → window via replaceState (paste/F5/copy link)
 *
 * Listeners must NOT depend on pathname/search — otherwise navigate() re-runs sync and loops
 * with index `<Navigate to="/dev" />` (Maximum update depth). See mfe-run-modes.md § Router Pattern.
 *
 * Strips `/kpi` shell prefix from window path so MemoryRouter routes remain clean (tc/kh/*).
 */
export const MemoryRouterSync: React.FC = () => {
  const navigate = useNavigate();
  const location = useLocation();
  const locationRef = useRef(location);
  locationRef.current = location;

  const syncingFromWindowRef = useRef(false);

  // Window / shell → MemoryRouter (events only — initial route = initialEntries)
  useEffect(() => {
    const syncFromWindow = () => {
      const raw = window.location.pathname + window.location.search;
      const next = stripShellPrefix(raw);
      const current =
        locationRef.current.pathname + locationRef.current.search;
      if (next === current) return;
      syncingFromWindowRef.current = true;
      navigate(next, { replace: true });
    };

    const forceMenuPath = (e: Event) => {
      if (isStandalone) return;
      const detail = (e as CustomEvent<{ path?: string; exact?: boolean }>).detail;
      const path = detail?.path;
      if (!path) return;
      const raw = detail?.exact ? path : path + window.location.search;
      const next = stripShellPrefix(raw);
      const current =
        locationRef.current.pathname + locationRef.current.search;
      if (next === current) return;
      syncingFromWindowRef.current = true;
      navigate(next, { replace: true });
    };

    window.addEventListener('single-spa:routing-event', syncFromWindow);
    window.addEventListener('popstate', syncFromWindow);
    window.addEventListener('linm:nav:force-path', forceMenuPath);
    if (!isStandalone) {
      syncFromWindow();
    }
    return () => {
      window.removeEventListener('single-spa:routing-event', syncFromWindow);
      window.removeEventListener('popstate', syncFromWindow);
      window.removeEventListener('linm:nav:force-path', forceMenuPath);
    };
  }, [navigate]);

  // MemoryRouter → address bar (standalone dev only)
  useEffect(() => {
    if (!isStandalone) return;
    if (syncingFromWindowRef.current) {
      syncingFromWindowRef.current = false;
      return;
    }

    const next = location.pathname + location.search;
    const current = window.location.pathname + window.location.search;
    if (next !== current) {
      window.history.replaceState(null, '', next);
    }
  }, [location.pathname, location.search]);

  return null;
};

export default MemoryRouterSync;
