/**
 * ERP KPI standalone mock sidebar — menu from devRoutes.ts (same links as /dev grid).
 */
import React, { useState, useEffect, useCallback } from 'react';
import { useLocation, useNavigate } from 'react-router-dom';
import {
  Sidebar, useResponsive, BREAKPOINTS,
  isSidebarCollapsed as getSidebarPref, setSidebarCollapsed,
} from '@linm-soft-org/linm-web-common-components';
import { DEV_MODULES } from '../dev/devRoutes';
import { devModulesToNavSections } from './devModulesToNavSections';
import { STANDALONE_NAV_CONFIG } from './standaloneNavConfig';

export const StandaloneMockNav: React.FC = () => {
  const location = useLocation();
  const navigate = useNavigate();
  const { isMobile, isSmallDesktop } = useResponsive();

  const [isSidebarCollapsed, setIsSidebarCollapsed] = useState(() => {
    if (typeof window === 'undefined') return false;
    const w = window.innerWidth;
    if (w < BREAKPOINTS.mobile) return false;
    if (w < BREAKPOINTS.tablet) return true;
    return getSidebarPref();
  });

  const [isMobileSidebarOpen, setIsMobileSidebarOpen] = useState(false);

  useEffect(() => {
    if (isSmallDesktop && !isSidebarCollapsed) {
      setIsSidebarCollapsed(true);
    } else if (!isMobile && !isSmallDesktop) {
      setIsSidebarCollapsed(getSidebarPref());
    } else if (isMobile) {
      setIsSidebarCollapsed(false);
    }
  }, [isMobile, isSmallDesktop, isSidebarCollapsed]);

  useEffect(() => {
    const handler = () => setIsMobileSidebarOpen((prev) => !prev);
    window.addEventListener('linm:nav:toggle-mobile', handler);
    return () => window.removeEventListener('linm:nav:toggle-mobile', handler);
  }, []);

  useEffect(() => {
    document.documentElement.style.setProperty(
      '--sidebar-width',
      isSidebarCollapsed ? '64px' : '280px',
    );
  }, [isSidebarCollapsed]);

  const handleToggleSidebar = useCallback(() => {
    setIsSidebarCollapsed((prev) => {
      const next = !prev;
      if (!isMobile) setSidebarCollapsed(next);
      return next;
    });
  }, [isMobile]);

  const handleNavigate = useCallback(
    (path: string) => {
      navigate(path);
      if (isMobile) setIsMobileSidebarOpen(false);
    },
    [isMobile, navigate],
  );

  const handleLogout = useCallback(() => navigate('/dev'), [navigate]);

  const sections = devModulesToNavSections(DEV_MODULES);
  const { logoLabel } = STANDALONE_NAV_CONFIG;

  return (
    <Sidebar
      sections={sections}
      activePath={location.pathname}
      userName="Dev Standalone"
      userRole="Developer"
      userInitials="DS"
      onNavigate={handleNavigate}
      onLogout={handleLogout}
      isCollapsed={isSidebarCollapsed}
      onToggleCollapse={handleToggleSidebar}
      isMobile={isMobile}
      isSmallDesktop={isSmallDesktop}
      isOpen={isMobileSidebarOpen}
      logoLabel={logoLabel}
    />
  );
};

export default StandaloneMockNav;
